def caesar(s, k):
    result = []
    k = k % 26  # Normalize k to 0-25 range

    for char in s:
        if char.isupper():
            shifted = (ord(char) - ord('A') + k) % 26
            result.append(chr(shifted + ord('A')))
        elif char.islower():
            shifted = (ord(char) - ord('a') + k) % 26
            result.append(chr(shifted + ord('a')))
        else:
            result.append(char)

    return ''.join(result)
```

